<template><div class="panel"><div class="section-head"><div><h2>操作日志</h2><p>系统写操作的脱敏审计记录。</p></div><el-button @click="load">刷新</el-button></div><el-table :data="rows"><el-table-column prop="operatedAt" label="时间" width="180"/><el-table-column prop="username" label="用户"/><el-table-column prop="method" label="方法" width="80"/><el-table-column prop="path" label="接口"/><el-table-column prop="durationMs" label="耗时(ms)"/><el-table-column label="结果"><template #default="s"><el-tag :type="s.row.success?'success':'danger'">{{s.row.success?'成功':'失败'}}</el-tag></template></el-table-column><el-table-column prop="errorMessage" label="错误" show-overflow-tooltip/></el-table><el-pagination v-model:current-page="query.page" :page-size="query.size" :total="total" layout="total, prev, pager, next" @current-change="load"/></div></template><script setup>import{onMounted,reactive,ref}from'vue';import http from'../api/http';const rows=ref([]),total=ref(0);const query=reactive({page:1,size:5});/** 加载操作日志。 */async function load(){const response=await http.get('/system/operation-logs',{params:query});rows.value=response.data.items;total.value=response.data.total}onMounted(load)</script>
<!-- 操作日志页面：展示系统写操作的脱敏审计记录。 -->
